// fshl(X, 0, Y) --> shl(X, and(Y, BitWidth - 1)) if bitwidth is a power-of-2
if (IID == Intrinsic::fshl && isPowerOf2_32(BitWidth) &&
    match(Op1, m_ZeroInt())) {
    Value *Op2 = II->getArgOperand(2);
    Value *And = Builder.CreateAnd(Op2, ConstantInt::get(Ty, BitWidth - 1));
    return BinaryOperator::CreateShl(Op0, And);
}
```

But the current code at lines 2232-2241 has a MORE sophisticated version:
```cpp
// fshl(X, 0, Y) --> shl X, (and Y, BW-1) or shl X, Y
// fshl(X, undef, Y) --> shl X, (and Y, BW-1) or shl X, Y
if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())) {
    ConstantRange ShAmtCR = computeConstantRangeIncludingKnownBits(
        II->getArgOperand(2), /*ForSigned=*/false, SQ.getWithInstruction(II));
    Value *ShAmt = II->getArgOperand(2);
    // If we can't prove the shift amount is less than the bitwidth, mask it.
    if (!ShAmtCR.getUnsignedMax().ult(BitWidth))
        ShAmt = Builder.CreateAnd(ShAmt, ConstantInt::get(Ty, BitWidth - 1));
    return BinaryOperator::CreateShl(Op0, ShAmt);
}
```

This is more sophisticated because:
1. It handles both `m_ZeroInt()` and `m_Undef()`
2. It checks the range of the shift amount to decide whether masking is needed
3. It doesn't require `isPowerOf2_32(BitWidth)` 

